mapper.select:
SELECT 
  FROM er.tn_eucr_crdt_dtl d
 WHERE d.eucr_id  = #{eucrId}
   AND d.batch_no = #{batchNo}
   AND NOW() BETWEEN d.use_bgng_dt AND d.use_end_dt
 ORDER BY d.crdt_no

SELECT 
  FROM er.tn_eucr_crdt_dtl d
 WHERE d.eucr_id = #{eucrId}
   AND d.crdt_no = #{crdtNo}
   AND NOW() BETWEEN d.use_bgng_dt AND d.use_end_dt

mapper.update:
UPDATE er.tn_eucr_crdt_dtl
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE eucr_id = #{eucrId}
   AND crdt_no = #{crdtNo}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

choose.otherwise:
SELECT d.crdt_no AS crdt_no, d.eucr_id AS eucr_id, d.batch_no AS batch_no, e.oprtr_id AS oprtr_id, o.oprtr_nm AS oprtr_nm, e.rprt_yr AS rprt_yr FROM er.tn_eucr_crdt_dtl d JOIN er.tn_eucr e ON e.eucr_id = d.eucr_id AND NOW() BETWEEN e.use_bgng_dt AND e.use_end_dt JOIN com.tn_oprtr o ON o.oprtr_id = e.oprtr_id AND NOW() BETWEEN o.use_bgng_dt AND o.use_end_dt WHERE NOW() BETWEEN d.use_bgng_dt AND d.use_end_dt AND d.crdt_no IN
#{cn}
AND d.eucr_id != #{excludeEucrId}
ORDER BY d.eucr_id, d.crdt_no
